BEGIN TRANSACTION;
CREATE TABLE IF NOT EXISTS "admin_users" (
	"id"	TEXT DEFAULT (lower(hex(randomblob(16)))),
	"full_name"	TEXT NOT NULL,
	"email"	TEXT NOT NULL UNIQUE COLLATE NOCASE,
	"password_hash"	TEXT NOT NULL,
	"status"	TEXT NOT NULL DEFAULT 'active' CHECK("status" IN ('active', 'suspended')),
	"created_at"	TEXT NOT NULL DEFAULT (strftime('%Y-%m-%dT%H:%M:%SZ', 'now')),
	"last_login"	TEXT,
	"super_admin"	INTEGER NOT NULL DEFAULT 0,
	PRIMARY KEY("id")
);
CREATE TABLE IF NOT EXISTS "audit_logs" (
	"id"	TEXT DEFAULT (lower(hex(randomblob(16)))),
	"admin_id"	TEXT NOT NULL,
	"action"	TEXT NOT NULL,
	"entity_type"	TEXT NOT NULL,
	"entity_id"	TEXT,
	"description"	TEXT,
	"ip_address"	TEXT,
	"created_at"	TEXT NOT NULL DEFAULT (strftime('%Y-%m-%dT%H:%M:%SZ', 'now')),
	PRIMARY KEY("id"),
	FOREIGN KEY("admin_id") REFERENCES "admin_users"("id")
);
CREATE TABLE IF NOT EXISTS "buyer_profiles" (
	"id"	TEXT DEFAULT (lower(hex(randomblob(16)))),
	"user_id"	TEXT NOT NULL UNIQUE,
	"total_orders"	INTEGER NOT NULL DEFAULT 0,
	"total_spent"	REAL NOT NULL DEFAULT 0.00,
	"created_at"	TEXT NOT NULL DEFAULT (strftime('%Y-%m-%dT%H:%M:%SZ', 'now')),
	PRIMARY KEY("id"),
	FOREIGN KEY("user_id") REFERENCES "users"("id") ON DELETE CASCADE
);
CREATE TABLE IF NOT EXISTS "cart_items" (
	"id"	TEXT DEFAULT (lower(hex(randomblob(16)))),
	"cart_id"	TEXT NOT NULL,
	"listing_id"	TEXT NOT NULL,
	"quantity"	INTEGER NOT NULL DEFAULT 1 CHECK("quantity" > 0),
	"variant"	TEXT,
	"added_at"	TEXT NOT NULL DEFAULT (strftime('%Y-%m-%dT%H:%M:%SZ', 'now')),
	UNIQUE("cart_id","listing_id"),
	PRIMARY KEY("id"),
	FOREIGN KEY("cart_id") REFERENCES "carts"("id") ON DELETE CASCADE,
	FOREIGN KEY("listing_id") REFERENCES "listings"("id")
);
CREATE TABLE IF NOT EXISTS "carts" (
	"id"	TEXT DEFAULT (lower(hex(randomblob(16)))),
	"buyer_id"	TEXT NOT NULL UNIQUE,
	"updated_at"	TEXT NOT NULL DEFAULT (strftime('%Y-%m-%dT%H:%M:%SZ', 'now')),
	PRIMARY KEY("id"),
	FOREIGN KEY("buyer_id") REFERENCES "buyer_profiles"("id") ON DELETE CASCADE
);
CREATE TABLE IF NOT EXISTS "categories" (
	"id"	TEXT DEFAULT (lower(hex(randomblob(16)))),
	"parent_id"	TEXT,
	"name"	TEXT NOT NULL,
	"slug"	TEXT NOT NULL UNIQUE,
	"icon"	TEXT,
	PRIMARY KEY("id"),
	FOREIGN KEY("parent_id") REFERENCES "categories"("id") ON DELETE SET NULL
);
CREATE TABLE IF NOT EXISTS "listings" (
	"id"	TEXT DEFAULT (lower(hex(randomblob(16)))),
	"product_id"	TEXT NOT NULL,
	"seller_id"	TEXT NOT NULL,
	"price"	REAL NOT NULL CHECK("price" > 0),
	"rrp"	REAL,
	"stock_qty"	INTEGER NOT NULL DEFAULT 0 CHECK("stock_qty" >= 0),
	"condition"	TEXT NOT NULL DEFAULT 'new' CHECK("condition" IN ('new', 'open_box', 'used_good', 'used_fair', 'for_parts')),
	"warranty"	TEXT,
	"sku"	TEXT,
	"status"	TEXT NOT NULL DEFAULT 'draft' CHECK("status" IN ('draft', 'live', 'paused', 'removed')),
	"image_urls"	TEXT,
	"created_at"	TEXT NOT NULL DEFAULT (strftime('%Y-%m-%dT%H:%M:%SZ', 'now')),
	"updated_at"	TEXT NOT NULL DEFAULT (strftime('%Y-%m-%dT%H:%M:%SZ', 'now')),
	PRIMARY KEY("id"),
	FOREIGN KEY("product_id") REFERENCES "products"("id"),
	FOREIGN KEY("seller_id") REFERENCES "seller_profiles"("id")
);
CREATE TABLE IF NOT EXISTS "order_items" (
	"id"	TEXT DEFAULT (lower(hex(randomblob(16)))),
	"order_id"	TEXT NOT NULL,
	"listing_id"	TEXT,
	"product_name"	TEXT NOT NULL,
	"seller_name"	TEXT NOT NULL,
	"unit_price"	REAL NOT NULL,
	"quantity"	INTEGER NOT NULL CHECK("quantity" > 0),
	"line_total"	REAL NOT NULL,
	PRIMARY KEY("id"),
	FOREIGN KEY("listing_id") REFERENCES "listings"("id") ON DELETE SET NULL,
	FOREIGN KEY("order_id") REFERENCES "orders"("id") ON DELETE CASCADE
);
CREATE TABLE IF NOT EXISTS "orders" (
	"id"	TEXT,
	"buyer_id"	TEXT NOT NULL,
	"delivery_address_id"	TEXT,
	"ref_number"	TEXT NOT NULL UNIQUE,
	"subtotal"	REAL NOT NULL DEFAULT 0,
	"discount"	REAL NOT NULL DEFAULT 0,
	"vat"	REAL NOT NULL DEFAULT 0,
	"total"	REAL NOT NULL DEFAULT 0,
	"status"	TEXT NOT NULL DEFAULT 'pending',
	"notes"	TEXT,
	"placed_at"	TEXT NOT NULL,
	"updated_at"	TEXT NOT NULL,
	PRIMARY KEY("id")
);
CREATE TABLE IF NOT EXISTS "payments" (
	"id"	TEXT DEFAULT (lower(hex(randomblob(16)))),
	"order_id"	TEXT NOT NULL UNIQUE,
	"yoko_txn_id"	TEXT NOT NULL UNIQUE,
	"auth_code"	TEXT NOT NULL,
	"card_masked"	TEXT,
	"card_type"	TEXT,
	"cardholder"	TEXT,
	"amount"	REAL NOT NULL,
	"currency"	TEXT NOT NULL DEFAULT 'ZAR',
	"status"	TEXT NOT NULL CHECK("status" IN ('confirmed', 'failed', 'refunded')),
	"three_ds_verified"	INTEGER NOT NULL DEFAULT 0 CHECK("three_ds_verified" IN (0, 1)),
	"paid_at"	TEXT NOT NULL DEFAULT (strftime('%Y-%m-%dT%H:%M:%SZ', 'now')),
	PRIMARY KEY("id"),
	FOREIGN KEY("order_id") REFERENCES "orders"("id")
);
CREATE TABLE IF NOT EXISTS "products" (
	"id"	TEXT DEFAULT (lower(hex(randomblob(16)))),
	"category_id"	TEXT NOT NULL,
	"name"	TEXT NOT NULL,
	"brand"	TEXT,
	"model_number"	TEXT,
	"description"	TEXT NOT NULL,
	"avg_rating"	REAL DEFAULT 0.00,
	"review_count"	INTEGER NOT NULL DEFAULT 0,
	"tags"	TEXT,
	"created_at"	TEXT NOT NULL DEFAULT (strftime('%Y-%m-%dT%H:%M:%SZ', 'now')),
	PRIMARY KEY("id"),
	FOREIGN KEY("category_id") REFERENCES "categories"("id")
);
CREATE TABLE IF NOT EXISTS "seller_profiles" (
	"id"	TEXT DEFAULT (lower(hex(randomblob(16)))),
	"user_id"	TEXT NOT NULL UNIQUE,
	"store_name"	TEXT NOT NULL,
	"store_bio"	TEXT,
	"rating"	REAL DEFAULT 0.00 CHECK("rating" BETWEEN 0 AND 5),
	"total_sales"	INTEGER NOT NULL DEFAULT 0,
	"verified"	INTEGER NOT NULL DEFAULT 0 CHECK("verified" IN (0, 1)),
	"created_at"	TEXT NOT NULL DEFAULT (strftime('%Y-%m-%dT%H:%M:%SZ', 'now')),
	PRIMARY KEY("id"),
	FOREIGN KEY("user_id") REFERENCES "users"("id") ON DELETE CASCADE
);
CREATE TABLE IF NOT EXISTS "shipping_options" (
	"id"	TEXT DEFAULT (lower(hex(randomblob(16)))),
	"listing_id"	TEXT NOT NULL,
	"method"	TEXT NOT NULL CHECK("method" IN ('standard', 'express', 'pickup')),
	"fee"	REAL NOT NULL DEFAULT 0.00,
	"dispatch_days"	INTEGER NOT NULL DEFAULT 2,
	"provider"	TEXT,
	"nationwide"	INTEGER NOT NULL DEFAULT 1 CHECK("nationwide" IN (0, 1)),
	PRIMARY KEY("id"),
	FOREIGN KEY("listing_id") REFERENCES "listings"("id") ON DELETE CASCADE
);
CREATE TABLE IF NOT EXISTS "users" (
	"id"	TEXT DEFAULT (lower(hex(randomblob(4))) || '-' || lower(hex(randomblob(2))) || '-4' || substr(lower(hex(randomblob(2))), 2) || '-' || substr('89ab', abs(random()) % 4 + 1, 1) || substr(lower(hex(randomblob(2))), 2) || '-' || lower(hex(randomblob(6)))),
	"full_name"	TEXT NOT NULL,
	"email"	TEXT NOT NULL UNIQUE COLLATE NOCASE,
	"phone"	TEXT NOT NULL,
	"password_hash"	TEXT NOT NULL,
	"role"	TEXT NOT NULL CHECK("role" IN ('buyer', 'seller')),
	"status"	TEXT NOT NULL DEFAULT 'active' CHECK("status" IN ('active', 'suspended', 'deleted')),
	"email_verified"	INTEGER NOT NULL DEFAULT 0 CHECK("email_verified" IN (0, 1)),
	"profile_img"	TEXT,
	"created_at"	TEXT NOT NULL DEFAULT (strftime('%Y-%m-%dT%H:%M:%SZ', 'now')),
	"updated_at"	TEXT NOT NULL DEFAULT (strftime('%Y-%m-%dT%H:%M:%SZ', 'now')),
	"last_login"	TEXT,
	"address_street"	TEXT DEFAULT '',
	"address_city"	TEXT DEFAULT '',
	"address_postal"	TEXT DEFAULT '',
	"address_province"	TEXT DEFAULT '',
	"address_country"	TEXT DEFAULT 'South Africa',
	PRIMARY KEY("id")
);
