CREATE INDEX IF NOT EXISTS "ix_admin_email" ON "admin_users" (
	"email"
);
CREATE INDEX IF NOT EXISTS "ix_auditlog_admin" ON "audit_logs" (
	"admin_id"
);
CREATE INDEX IF NOT EXISTS "ix_auditlog_created" ON "audit_logs" (
	"created_at"
);
CREATE INDEX IF NOT EXISTS "ix_auditlog_entity" ON "audit_logs" (
	"entity_type",
	"entity_id"
);
CREATE INDEX IF NOT EXISTS "ix_buyer_user" ON "buyer_profiles" (
	"user_id"
);
CREATE INDEX IF NOT EXISTS "ix_cartitems_cart" ON "cart_items" (
	"cart_id"
);
CREATE INDEX IF NOT EXISTS "ix_cartitems_listing" ON "cart_items" (
	"listing_id"
);
CREATE INDEX IF NOT EXISTS "ix_categories_parent" ON "categories" (
	"parent_id"
);
CREATE INDEX IF NOT EXISTS "ix_categories_slug" ON "categories" (
	"slug"
);
CREATE INDEX IF NOT EXISTS "ix_listings_live" ON "listings" (
	"status",
	"price"
) WHERE "status" = 'live';
CREATE INDEX IF NOT EXISTS "ix_listings_price" ON "listings" (
	"price"
);
CREATE INDEX IF NOT EXISTS "ix_listings_product" ON "listings" (
	"product_id"
);
CREATE INDEX IF NOT EXISTS "ix_listings_seller" ON "listings" (
	"seller_id"
);
CREATE INDEX IF NOT EXISTS "ix_listings_status" ON "listings" (
	"status"
);
CREATE INDEX IF NOT EXISTS "ix_orderitems_listing" ON "order_items" (
	"listing_id"
);
CREATE INDEX IF NOT EXISTS "ix_orderitems_order" ON "order_items" (
	"order_id"
);
CREATE INDEX IF NOT EXISTS "ix_payments_order" ON "payments" (
	"order_id"
);
CREATE INDEX IF NOT EXISTS "ix_payments_yoko" ON "payments" (
	"yoko_txn_id"
);
CREATE INDEX IF NOT EXISTS "ix_products_brand" ON "products" (
	"brand"
);
CREATE INDEX IF NOT EXISTS "ix_products_category" ON "products" (
	"category_id"
);
CREATE INDEX IF NOT EXISTS "ix_seller_user" ON "seller_profiles" (
	"user_id"
);
CREATE INDEX IF NOT EXISTS "ix_shipping_listing" ON "shipping_options" (
	"listing_id"
);
