	"email"
);
CREATE INDEX IF NOT EXISTS "ix_users_role" ON "users" (
	"role"
);
CREATE INDEX IF NOT EXISTS "ix_users_status" ON "users" (
	"status"
);
CREATE TRIGGER trg_carts_updated
    AFTER UPDATE ON carts
    BEGIN
        UPDATE carts SET updated_at = strftime('%Y-%m-%dT%H:%M:%SZ','now') WHERE id = NEW.id;
    END;
CREATE TRIGGER trg_listings_updated
    AFTER UPDATE ON listings
    BEGIN
        UPDATE listings SET updated_at = strftime('%Y-%m-%dT%H:%M:%SZ','now') WHERE id = NEW.id;
    END;
CREATE TRIGGER trg_orderitem_decrement_stock
    AFTER INSERT ON order_items
    WHEN NEW.listing_id IS NOT NULL
    BEGIN
        UPDATE listings
        SET stock_qty = stock_qty - NEW.quantity
        WHERE id = NEW.listing_id AND stock_qty >= NEW.quantity;
    END;
CREATE TRIGGER trg_users_updated
    AFTER UPDATE ON users
    BEGIN
        UPDATE users SET updated_at = strftime('%Y-%m-%dT%H:%M:%SZ','now') WHERE id = NEW.id;
    END;
COMMIT;
